import{_ as o,o as a,c,a3 as t}from"./chunks/framework.aYYe0dfI.js";const m=JSON.parse('{"title":"Namespace clore::net::anthropic::schema","description":"命名空间 clore::net::anthropic::schema 负责定义与 Anthropic API 交互所涉及的架构元素。它提供了两个核心函数模板：function_tool 用于向 API 注册可被模型调用的工具，需要提供工具名称和描述，并通过模板参数指定输入架构；response_format 则用于获取与特定预定义类型关联的响应格式标识符。此外，该命名空间还包含 name 和 description 变量，这些元素共同构成了定义工具调用和响应格式约定的结构化基础设施，在请求构造与响应解析中起到关键的契约作用。","frontmatter":{"title":"Namespace clore::net::anthropic::schema","description":"命名空间 clore::net::anthropic::schema 负责定义与 Anthropic API 交互所涉及的架构元素。它提供了两个核心函数模板：function_tool 用于向 API 注册可被模型调用的工具，需要提供工具名称和描述，并通过模板参数指定输入架构；response_format 则用于获取与特定预定义类型关联的响应格式标识符。此外，该命名空间还包含 name 和 description 变量，这些元素共同构成了定义工具调用和响应格式约定的结构化基础设施，在请求构造与响应解析中起到关键的契约作用。","layout":"doc","template":"doc"},"headers":[],"relativePath":"zh/clore/namespaces/clore/net/anthropic/schema/index.md","filePath":"zh/clore/namespaces/clore/net/anthropic/schema/index.md"}'),n={name:"zh/clore/namespaces/clore/net/anthropic/schema/index.md"};function r(i,e,s,l,h,p){return a(),c("div",null,[...e[0]||(e[0]=[t('<h1 id="namespace-clore-net-anthropic-schema" tabindex="-1">Namespace <code>clore::net::anthropic::schema</code> <a class="header-anchor" href="#namespace-clore-net-anthropic-schema" aria-label="Permalink to &quot;Namespace `clore::net::anthropic::schema`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>命名空间 <code>clore::net::anthropic::schema</code> 负责定义与 Anthropic API 交互所涉及的架构元素。它提供了两个核心函数模板：<code>function_tool</code> 用于向 API 注册可被模型调用的工具，需要提供工具名称和描述，并通过模板参数指定输入架构；<code>response_format</code> 则用于获取与特定预定义类型关联的响应格式标识符。此外，该命名空间还包含 <code>name</code> 和 <code>description</code> 变量，这些元素共同构成了定义工具调用和响应格式约定的结构化基础设施，在请求构造与响应解析中起到关键的契约作用。</p><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-net-anthropic-schema-function-tool" tabindex="-1"><code>clore::net::anthropic::schema::function_tool</code> <a class="header-anchor" href="#clore-net-anthropic-schema-function-tool" aria-label="Permalink to &quot;`clore::net::anthropic::schema::function_tool`&quot;">​</a></h3><p>Declaration: <code>network/anthropic.cppm:755</code></p><p>Definition: <code>network/anthropic.cppm:755</code></p><p>Implementation: <a href="./../../../../../modules/anthropic/"><code>Module anthropic</code></a></p><p><code>clore::net::anthropic::schema::function_tool</code> 是一个模板函数，用于向 Anthropic API 注册一个可被模型调用的函数工具。调用者需提供工具的名称和描述（均为 <code>std::string</code> 类型），并通过模板参数 <code>T</code> 指明该工具的输入架构（如表示函数参数的结构体类型）。函数返回一个 <code>int</code> 值，表示注册是否成功（例如非零值表示错误）。此函数是定义工具调用契约的关键入口，确保模型能够根据提供的名称和描述正确调用函数，并使用 <code>T</code> 所描述的结构化参数。</p><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Constructing a <code>FunctionToolDefinition</code> for tool use in Anthropic API calls</li></ul><h3 id="clore-net-anthropic-schema-response-format" tabindex="-1"><code>clore::net::anthropic::schema::response_format</code> <a class="header-anchor" href="#clore-net-anthropic-schema-response-format" aria-label="Permalink to &quot;`clore::net::anthropic::schema::response_format`&quot;">​</a></h3><p>Declaration: <code>network/anthropic.cppm:750</code></p><p>Definition: <code>network/anthropic.cppm:750</code></p><p>Implementation: <a href="./../../../../../modules/anthropic/"><code>Module anthropic</code></a></p><p>函数模板 <code>clore::net::anthropic::schema::response_format</code> 接受一个模板参数 <code>T</code> 并返回一个 <code>int</code>，该整数表示与 <code>T</code> 相关联的响应格式标识符。调用者需要保证 <code>T</code> 是库中预定义的可用于指定响应格式的类型；函数本身不接受任何运行时参数。返回的整数值可在后续操作（如设置请求选项或解析响应）中用于选择或标识对应的格式。</p><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Obtaining Anthropic API response format</li><li>Configuration for API calls</li></ul><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../">Namespace clore::net::anthropic</a></li></ul>',20)])])}const u=o(n,[["render",r]]);export{m as __pageData,u as default};
